def verify_signature(payload_body: bytes, signature_header: str, secret: str) -> bool:
    """
    Verify the HMAC-SHA256 signature of the incoming webhook request.
    Partners sign the request body with a shared secret.
    """
    if not secret:
        logger.warning("WEBHOOK_SECRET is not configured. Skipping signature verification.")
        return False

    if not signature_header:
        logger.warning("No signature header provided in the request.")
        return False

    # Support formats: "sha256=<hex>" or just "<hex>"
    if signature_header.startswith("sha256="):
        provided_signature = signature_header[7:]
    else:
        provided_signature = signature_header

    expected_signature = hmac.new(
        secret.encode("utf-8"),
        payload_body,
        hashlib.sha256,
    ).hexdigest()

    return hmac.compare_digest(expected_signature, provided_signature)


def verify_ip(request) -> bool:
    """
    Optionally verify the request comes from a known partner IP.
    """
    if not ALLOWED_PARTNER_IPS or ALLOWED_PARTNER_IPS == [""]:
        # No IP allowlist configured; skip check
        return True

    # Check X-Forwarded-For for Cloud Function behind load balancer
    forwarded_for = request.headers.get("X-Forwarded-For", "")
    if forwarded_for:
        client_ip = forwarded_for.split(",")[0].strip()
    else:
        client_ip = request.remote_addr

    if client_ip in ALLOWED_PARTNER_IPS:
        return True

    logger.warning(f"Request from unauthorized IP: {client_ip}")
    return False


def validate_payload(payload: dict) -> tuple[bool, str]:
    """
    Validate the webhook payload structure and required fields.
    """
    required_fields = ["event_type", "event_id", "timestamp", "data"]

    for field in required_fields:
        if field not in payload:
            return False, f"Missing required field: {field}"

    # Validate event type
    event_type = payload.get("event_type")
    if event_type not in SUPPORTED_EVENTS:
        return False, f"Unsupported event type: {event_type}"

    # Validate event_id is a non-empty string
    event_id = payload.get("event_id")
    if not isinstance(event_id, str) or not event_id.strip():
        return False, "event_id must be a non-empty string"

    # Validate timestamp
    timestamp = payload.get("timestamp")
    if not isinstance(timestamp, (str, int, float)):
        return False, "timestamp must be a string (ISO format) or numeric (epoch)"

    # Validate data is a dictionary
    data = payload.get("data")
    if not isinstance(data, dict):
        return False, "data must be a JSON object"

    # Validate payment-specific fields in data
    if event_type.startswith("payment."):
        payment_required = ["payment_id", "amount", "currency"]
        for field in payment_required:
            if field not in data:
                return False, f"Missing required payment field in data: {field}"

        # Validate amount is a positive number
        amount = data.get("amount")
        if not isinstance(amount, (int, float)) or amount < 0:
            return False, "amount must be a non-negative number"

        # Validate currency is a 3-letter code
        currency = data.get("currency")
        if not isinstance(currency, str) or len(currency) != 3:
            return False, "currency must be a 3-letter ISO currency code"

    return True, ""


